// Ne garder que les emails qui ressemblent à une candidature (sujet ou pièce jointe CV)
const items = $input.all();
const subjectKeywords = /candidature|cv|application|postule|resume|curriculum|offre|emploi|stage|pfe|stagiaire|internship|développeur|developpeur|developer|full[\s-]*stack|ingenieur|ingénieur/i;

const filtered = items.filter((item) => {
  const subject = String(item.json.subject || '').toLowerCase();
  const bin = item.binary || {};
  const attKeys = Object.keys(bin).filter((k) => /^attachment_?\d*$/i.test(k) || k === 'data');
  let hasCvAttachment = false;
  for (const k of attKeys) {
    const b = bin[k];
    if (!b) continue;
    const fn = String(b.fileName || '');
    const mime = String(b.mimeType || b.mime || '');
    if (/\.(pdf|docx?)$/i.test(fn) || /pdf|msword|wordprocessingml|officedocument/i.test(mime)) {
      hasCvAttachment = true;
      break;
    }
  }
  return subjectKeywords.test(subject) || hasCvAttachment;
});

return filtered;

const items = $input.all();
const baseUrl = 'http://127.0.0.1:9000';

return items.map((item) => {
  const uploadUrl = String(item.json.uploadUrl || '').trim();
  let fullUploadUrl = baseUrl + (uploadUrl.startsWith('/') ? uploadUrl : '/' + uploadUrl);
  if (!fullUploadUrl.startsWith('http')) fullUploadUrl = baseUrl + '/' + (uploadUrl.replace(/^\//, '') || 'cvs');
  const bin = item.binary || {};
  const attKey = Object.keys(bin).find((k) => k.startsWith('attachment_'));
  if (attKey && attKey !== 'attachment_0') bin.attachment_0 = bin[attKey];
  return { json: { ...item.json, fullUploadUrl }, binary: bin };
});

const data = $input.first().json;
const offers = Array.isArray(data.offers) ? data.offers : [];
const merge = $('2 - Merge (Email + API response)').first().json;
const subjectRaw = String(merge.subject || '').trim();

function norm(s) {
  return String(s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/^re:\s*|^fwd:\s*/gi, '')
    .replace(/[\u2010-\u2015\u2212]/g, '-')
    .replace(/[_\u2013\u2014\-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const STOP = new Set(['le', 'la', 'les', 'des', 'une', 'pour', 'avec', 'stage', 'pfe', 'offre', 'emploi', 'candidature', 'poste', 'job', 'd', 'de', 'du', 'et', 'ou', 'the', 'a', 'an']);

function tokens(s) {
  return norm(s).split(/[^a-z0-9\u00c0-\u024f]+/).filter((t) => t.length > 1 && !STOP.has(t));
}

const subjN = norm(subjectRaw);
const subjTokens = new Set(tokens(subjectRaw));

const GROUPS = [
  { keys: ['devops', 'docker', 'aws', 'kubernetes', 'argo', 'terraform', 'jenkins', 'gitlab'], weight: 58 },
  { keys: ['data', 'analyst', 'bi', 'power', 'etl'], weight: 52 },
  { keys: ['full', 'stack', 'react', 'javascript', 'angular', 'vue'], weight: 48 },
  { keys: ['java', 'spring', 'boot'], weight: 42 },
  { keys: ['cloud', 'azure'], weight: 36 },
];

function scoreOffer(offer) {
  const title = String(offer.title || '');
  const tN = norm(title);
  let score = 0;
  for (const g of GROUPS) {
    const subHit = g.keys.some((k) => subjN.includes(k));
    const titHit = g.keys.some((k) => tN.includes(k));
    if (subHit && titHit) score += g.weight;
    if (subHit && !titHit) score -= 24;
  }
  if (subjN && tN && tN.length > 24 && subjN.length > 24 && (subjN.includes(tN) || tN.includes(subjN))) score += 88;
  let overlap = 0;
  for (const t of tokens(title)) {
    if (subjTokens.has(t)) overlap++;
  }
  score += overlap * 8;
  return score;
}

let best = null;
let bestScore = -1e9;
for (const o of offers) {
  const sc = scoreOffer(o);
  if (sc > bestScore) {
    bestScore = sc;
    best = o;
  }
}

const MIN_SCORE = 18;
let offerTitle;
let offerDescription;

if (best && bestScore >= MIN_SCORE) {
  offerTitle = best.title;
  offerDescription = [best.company, best.location].filter(Boolean).join(' - ');
} else {
  offerTitle = subjectRaw.replace(/^re:\s*|^fwd:\s*/gi, '').trim() || 'Poste';
  offerDescription = '';
}

return [{ json: { offerTitle, offerDescription, subject: subjectRaw, _offerMatchScore: bestScore } }];

const cvRes = $input.first().json;
const offer = $('7 - Set Offer Context').first().json;
const init = $('1 - Initialize Candidate API').first().json;
const email = $('2 - Merge (Email + API response)').first().json;

const cvText = String(cvRes.text || '');
const offerTitle = String(offer.offerTitle || '');
const offerDescription = String(offer.offerDescription || '');
const subject = String(email.subject || '');
const fromVal = email.from && email.from.value && email.from.value[0];
const fromLine = fromVal ? `${fromVal.name || ''} <${fromVal.address}>`.trim() : String(email.from || '');
const bodySnippet = String(email.text || email.textPlain || '').slice(0, 2500);

const internalMatch = typeof offer._offerMatchScore === 'number' && Number.isFinite(offer._offerMatchScore) ? offer._offerMatchScore : null;
const CATALOG_MIN = 18;
const offerFromCatalog = internalMatch != null && internalMatch >= CATALOG_MIN;
const matchLine = internalMatch != null ? ('\n[Métadonnée PCA — matching sujet → catalogue] Score interne n8n : ' + internalMatch + ' (seuil dans ce workflow : ' + CATALOG_MIN + '). ' + (offerFromCatalog ? 'Offre catalogue retenue : le score mesure surtout l adéquation CV ↔ OFFRE CIBLE (titre + contexte), sans contredire fortement le SUJET (OBJET).' : 'Pas de match catalogue ferme : le titre OFFRE CIBLE suit le SUJET — le score mesure surtout l adéquation CV ↔ OBJET ; OFFRE CIBLE rappelle le même intitulé.')) : '';

const llmUserMessage = `CONTEXTE EMAIL (message reçu):\nRéférence A — SUJET (OBJET du mail, intention candidat) : ${subject}\nDe: ${fromLine}\nNom API: ${init.candidateName || init.fullName || ''}\nEmail API: ${init.email || ''}\nExtrait corps:\n${bodySnippet}\n\nRéférence B — OFFRE CIBLE (titre + contexte : ligne catalogue PCA si matching sujet→catalogue OK, sinon alignée sur le sujet) :\nTitre: ${offerTitle}\nContexte: ${offerDescription}${matchLine}\n\nTEXTE CV (décodé serveur PCA, tronqué) :\n${cvText.slice(0, 14000)}\n\nRÈGLE DE NOTATION — score (0-100) et décision : croiser A (OBJET) et B (OFFRE CIBLE) avec le CV. Si métadonnée PCA indique offre catalogue retenue : scorer surtout CV↔B, pénaliser hors-métier vs B ou contradiction forte avec A. Sinon : scorer surtout CV↔A ; B est le rappel du titre. Toujours pénaliser décalage stack/métier évident. Pas de score « bon CV en général » sans lien A/B.\n\nRÈGLE last_employer (flux n8n, comme le score — basé sur le TEXTE CV) : entreprise de l expérience la PLUS RÉCENTE (dates les plus tardives ou en cours). Beaucoup de CV mettent le plus récent en haut : c est alors la PREMIÈRE entrée de la section expériences, pas la dernière du document.\nAnalyse ce dossier et renvoie uniquement le JSON demandé.`;

const systemPrompt = `Tu es un expert RH PCA. Tu fusionnes l'email de candidature et le texte du CV.\nRéponds UNIQUEMENT avec un objet JSON valide (sans markdown), avec exactement ces clés :\nsummary, skills, experience, strengths, risks, score (0-100), decision (une parmi ACCEPTEE, REFUSEE, A REVOIR, NON_LISIBLE), offer_context, school, school_type (PUBLIC, PRIVE ou null), phone, experience_count, experience_duration, experience_years_avg, last_employer, candidate_name\nContraintes de format :\n- candidate_name : string obligatoire si le nom apparaît sur le CV (souvent en haut du document en majuscules). Source UNIQUEMENT le texte du CV. Interdit : nom de l'expéditeur du mail, champ « Nom API », nom de fichier PDF, ou toute métadonnée hors CV.\n- skills : string uniquement, compétences séparées par des virgules. Jamais tableau JSON ni accolades type liste.\n- experience : string uniquement, paragraphe ou blocs séparés par des retours à la ligne, lisible pour un RH. Jamais JSON imbriqué dans ce champ.\n- offer_context : 2 à 4 phrases en français ; mentionner explicitement le SUJET (OBJET), le titre OFFRE CIBLE, et si la note suit surtout le catalogue ou surtout le sujet (selon métadonnée PCA du message utilisateur).\n- summary, strengths, risks : prose française.\n- score : nombre 0-100 ; croiser CV avec A=SUJET et B=OFFRE CIBLE, priorité catalogue ou priorité sujet comme indiqué dans la règle du message utilisateur — pas d'évaluation générique.\n- decision : cohérente avec ce score et ces références A/B (pas une note en général).\n- last_employer : entreprise de l expérience la PLUS RÉCENTE (fin la plus tardive, ou en cours / présent). Si le CV classe du plus récent au plus ancien, prendre la PREMIÈRE entrée de la section Expériences, pas la dernière ligne du texte. Chaîne vide si inconnu.\nSi le CV est illisible ou trop court : NON_LISIBLE.`;

return [
  {
    json: {
      llmUserMessage,
      systemPrompt,
      candidatureId: init.id,
      offerTitle,
      offerDescription,
    },
  },
];

// Nœud n8n « 11 - Parse LLM JSON » : parse la réponse OpenAI puis corrige last_employer
// (texte CV + champ experience du LLM : année la plus récente).

const raw = $input.first().json
const content = raw.choices && raw.choices[0] && raw.choices[0].message && raw.choices[0].message.content
if (!content) throw new Error('Réponse OpenAI vide: ' + JSON.stringify(raw).slice(0, 500))
let s = String(content)
  .trim()
  .replace(/^```(?:json)?\s*/i, '')
  .replace(/\s*```$/, '')
  .trim()
let parsed
try {
  parsed = JSON.parse(s)
} catch (e) {
  throw new Error('JSON invalide: ' + e.message + ' — ' + s.slice(0, 300))
}
const meta = $('9 - Assemble LLM payload').first().json
const rawName =
  parsed.candidate_name ??
  parsed.candidateName ??
  parsed.full_name ??
  parsed.nom_candidat ??
  parsed.nomComplet
const candidate_name =
  rawName != null && String(rawName).trim() !== '' ? String(rawName).trim() : null

function nsp(str) {
  return String(str || '')
    .replace(/\s+/g, ' ')
    .trim()
}

/** Années dans une fenêtre de texte (bloc expérience + ligne au-dessus si besoin). */
function maxYearInWindow(txt, start, end) {
  const slice = String(txt || '').slice(Math.max(0, start), end)
  const years = [...slice.matchAll(/\b(19|20)\d{2}\b/g)]
    .map((mm) => parseInt(mm[0], 10))
    .filter((y) => y >= 1950 && y <= 2040)
  if (!years.length) return null
  return Math.max(...years)
}

/** Détail depuis le texte CV (PDF) : plusieurs lignes « poste — entreprise ». */
function lastEmployerFromCvDetailed(cv) {
  const txt = String(cv || '')
  const linePattern =
    /(?:Stagiaire|Stage|Développeur|Developer|Engineer|Ingénieur|Architecte|Consultant)[^\n–—]{0,90}[–—-]\s*([^\n,]+)/gi
  const matches = []
  let m
  while ((m = linePattern.exec(txt)) !== null) {
    if (!m[1]) continue
    const start = m.index
    let company = nsp(m[1])
    const idxParen = company.indexOf('(')
    if (idxParen > 0) company = nsp(company.slice(0, idxParen))
    const winStart = Math.max(0, start - 220)
    const winEnd = Math.min(txt.length, start + 380)
    const win = txt.slice(winStart, winEnd)
    let maxYear = maxYearInWindow(txt, winStart, winEnd)
    const ongoing = /\b(présent|present|actuel|actuelle|en\s+cours|current|now|today)\b/i.test(win)
    const yNow = new Date().getFullYear()
    let effectiveYear = ongoing ? Math.max(maxYear || yNow, yNow) : maxYear
    if (effectiveYear == null) effectiveYear = -1
    matches.push({ company, effectiveYear, start })
  }
  return matches
}

/** Entreprise + année depuis les lignes « … — Société — 2024 » du champ experience (LLM). */
function lastEmployerFromExperienceDetailed(exp) {
  const t = String(exp || '').replace(/\r/g, '\n')
  const out = []
  for (const line of t.split('\n')) {
    const parts = line.split(/[–—-]/).map((p) => nsp(p))
    if (parts.length < 2) continue
    const last = parts[parts.length - 1]
    const ym = last.match(/\b((?:19|20)\d{2})\b/)
    if (!ym) continue
    const y = parseInt(ym[1], 10)
    if (y < 1990 || y > 2040) continue
    const company = parts[parts.length - 2]
    if (!company || company.length < 2 || company.length > 85) continue
    out.push({ company, effectiveYear: y, start: 1e6 })
  }
  return out
}

function pickLatestEmployer(rows) {
  if (!rows.length) return null
  rows.sort((a, b) => {
    if (b.effectiveYear !== a.effectiveYear) return b.effectiveYear - a.effectiveYear
    return a.start - b.start
  })
  return rows[0].company
}

const cvText = String($('8 - Get CV text (PCA, no OpenAI)').first().json.text || '')
const fromCvRows = lastEmployerFromCvDetailed(cvText)
const fromExpRows = lastEmployerFromExperienceDetailed(parsed.experience)
const merged = [...fromCvRows, ...fromExpRows]
const fromHeuristic = pickLatestEmployer(merged)

const llmLe = parsed.last_employer != null ? nsp(parsed.last_employer) : ''
const last_employer = fromHeuristic || llmLe || null

return [
  {
    json: {
      ...parsed,
      candidatureId: meta.candidatureId,
      offerTitle: meta.offerTitle,
      offerDescription: meta.offerDescription,
      candidate_name,
      last_employer,
    },
  },
]

const root = $input.first().json;
const b = root.body && typeof root.body === 'object' && !Array.isArray(root.body) ? root.body : root;
function cleanEmail(e) {
  if (e == null) return '';
  let s = String(e).trim();
  if (s.toLowerCase().startsWith('mailto:')) s = s.slice(7).split('?')[0].trim();
  const m = s.match(/<([^>]+)>/);
  if (m) return m[1].trim();
  const bare = s.match(/\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/i);
  return bare ? bare[0] : s;
}
function cleanName(n) {
  if (n == null) return '';
  let s = String(n).trim();
  s = s.replace(/<[^>]+>/g, ' ').replace(/\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/gi, ' ');
  return s.replace(/\s+/g, ' ').trim();
}
const type = String(b.interviewType || '').toUpperCase();
let interviewTypeLabel = b.interviewTypeLabel;
if (!interviewTypeLabel) {
  if (type.includes('TECH')) interviewTypeLabel = 'Entretien technique';
  else if (type.includes('DIRECT') || type.includes('MANAG')) interviewTypeLabel = 'Entretien avec le directeur';
  else interviewTypeLabel = 'Entretien RH';
}
return [{
  json: {
    interviewId: b.interviewId,
    candidatureId: b.candidatureId,
    scheduledAt: b.scheduledAt,
    mode: b.mode,
    location: b.location,
    interviewType: b.interviewType,
    interviewTypeLabel,
    candidateName: cleanName(b.candidateName),
    email: cleanEmail(b.email),
    subject: String(b.subject || '').trim(),
  },
}];

